import type { ClonableMixin } from "../../core/Clonable.js";
import type { JSONSupport } from "../../core/JSONSupport.js";
import type { DomainUnion } from "./types.js";

export interface SubtypeProperties extends Partial<Pick<Subtype, "code" | "defaultValues" | "domains" | "name">> {}

export type Domains = Record<string, DomainUnion> | null;

/**
 * Subtypes categorize a subset of features in a layer that share the same attributes.
 * These subset of features are categorized based off the attribute value of the [layer.subtypeField](https://developers.arcgis.com/javascript/latest/references/core/layers/FeatureLayer/#subtypeField).
 * Subtypes can have default values and [domains](https://developers.arcgis.com/javascript/latest/references/core/layers/support/Domain/) assigned to their respective fields.
 * This class has no constructor.
 *
 * @since 4.28
 * @see [Introduction to subtypes](https://pro.arcgis.com/en/pro-app/latest/help/data/geodatabases/overview/an-overview-of-subtypes.htm)
 */
export default class Subtype extends SubtypeSuperclass {
  constructor(properties?: SubtypeProperties);
  /** The subtype unique identifier number. */
  accessor code: number;
  /** Name-value pairs of fields and their default field values associated with the subtype. */
  accessor defaultValues: { [key: string]: string | number | null; };
  /**
   * [Domains](https://developers.arcgis.com/javascript/latest/references/core/layers/support/Domain/) associated with the subtype. It is an object where the name of each property corresponds with the name of a field
   * containing a domain. If a field's domain is an instance of [InheritedDomain](https://developers.arcgis.com/javascript/latest/references/core/layers/support/InheritedDomain/), the application
   * will use the domain defined for the field from the layer. If the domain is an instance of
   * [CodedValueDomain](https://developers.arcgis.com/javascript/latest/references/core/layers/support/CodedValueDomain/) or [RangeDomain](https://developers.arcgis.com/javascript/latest/references/core/layers/support/RangeDomain/) then the domain is defined
   * specifically for the given feature type.
   */
  accessor domains: Domains | null | undefined;
  /** The subtype name. */
  accessor name: string;
}
declare const SubtypeSuperclass: typeof JSONSupport & typeof ClonableMixin